// ============================================================
// PASTE YOUR JOB DESCRIPTION BETWEEN THE BACKTICKS BELOW
// ============================================================

const jobDescription = `
Software Engineer – AI Products

We are looking for a talented Software Engineer to join our AI team.

Responsibilities:
- Design and build scalable backend services and APIs
- Collaborate with cross-functional teams on AI-driven product features
- Write clean, well-tested code in Python and/or JavaScript
- Participate in code reviews and architectural discussions

Requirements:
- 3+ years of software engineering experience
- Proficiency in Python, JavaScript/TypeScript
- Experience with REST APIs and cloud platforms (AWS/GCP/Azure)
- Familiarity with ML/AI concepts is a plus
- Strong problem-solving and communication skills

We offer competitive salary, remote-friendly environment, and growth opportunities.
`;

return [{
  json: {
    jobDescription: jobDescription.trim(),
    timestamp: new Date().toISOString()
  }
}];

const jobDescription = $input.first().json.jobDescription;

const systemPrompt = `You are a professional AI HR interviewer for a tech company. Your goal is to assess candidates in a friendly, structured conversation.

Job Description:
${jobDescription}

Interview Guidelines:
- Start with a warm welcome
- Ask about their background and motivation for applying
- Explore relevant technical experience with real examples
- Assess problem-solving and communication skills
- Allow time for candidate questions
- Close professionally with next steps

Be conversational, empathetic, and thorough. Ask smart follow-up questions.`;

const welcomeMessage = `Hello! Welcome and thank you for applying. I'm your AI interviewer today. Let's start — could you briefly introduce yourself and tell me what excites you most about this opportunity?`;

return [{
  json: {
    jobDescription,
    systemPrompt,
    welcomeMessage,
    agentName: `HR Bot – ${new Date().toLocaleDateString()}`
  }
}];

const workflowStaticData = $getWorkflowStaticData('global');

const agentId = $input.first().json.id;
const interviewLink = $input.first().json.call_link;
const jobDescription = $('Prepare Interview Agent').first().json.jobDescription;

workflowStaticData.agentId = agentId;
workflowStaticData.jobDescription = jobDescription;
workflowStaticData.interviewLink = interviewLink;

return [{
  json: {
    'Agent ID': agentId,
    'Agent Name': $('Prepare Interview Agent').first().json.agentName,
    'Interview Link': interviewLink,
    'Job Description': jobDescription,
    'System Prompt': $('Prepare Interview Agent').first().json.systemPrompt,
    'Welcome Message': $('Prepare Interview Agent').first().json.welcomeMessage
  }
}];

const resumeText = $input.first().json.text || $input.first().json.data || '';
const candidateName = $('📱 Telegram Resume Trigger').first().json.message.from.first_name + ' ' + ($('📱 Telegram Resume Trigger').first().json.message.from.last_name || '');
const chatId = $('📱 Telegram Resume Trigger').first().json.message.chat.id;
const telegramUsername = $('📱 Telegram Resume Trigger').first().json.message.from.username || 'N/A';

return [{
  json: {
    resumeText: resumeText.trim(),
    candidateName: candidateName.trim(),
    chatId,
    telegramUsername
  }
}];

const analysisText = $input.first().json.message.content;
let analysis;
try {
  const jsonMatch = analysisText.match(/```json\n([\s\S]*?)\n```/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[1]);
  } else {
    analysis = JSON.parse(analysisText);
  }
} catch(e) {
  analysis = {
    candidateName: $('Prepare Resume Data').first().json.candidateName,
    email: 'N/A', phone: 'N/A', yearsExperience: 0,
    currentRole: 'Unknown', topSkills: [],
    fitScore: 0, shortlisted: false,
    strengths: [], gaps: ['Could not parse resume'],
    summary: 'Analysis failed - please review manually.',
    rejectionReason: 'Automated parsing error'
  };
}

const chatId = $('Prepare Resume Data').first().json.chatId;
const telegramUsername = $('Prepare Resume Data').first().json.telegramUsername;
const interviewLink = $getWorkflowStaticData('global').interviewLink;

return [{
  json: {
    ...analysis,
    chatId,
    telegramUsername,
    interviewLink,
    appliedDate: new Date().toISOString()
  }
}];

const workflowStaticData = $getWorkflowStaticData('global');
const MY_AGENT_ID = workflowStaticData.agentId;
const jobDescription = workflowStaticData.jobDescription;
const webhookData = $input.first().json.body;
const receivedAgentId = webhookData.agent_id || webhookData.agentId || (webhookData.call_data && webhookData.call_data.agent_id);

if (receivedAgentId === MY_AGENT_ID && webhookData.event_type === 'call_ended') {
  return [{ json: { process: true, jobDescription, webhookData } }];
} else {
  return [{ json: { process: false, reason: receivedAgentId !== MY_AGENT_ID ? 'Different agent' : 'Call not finished yet' } }];
}

const analysisText = $input.first().json.message.content;
let analysis;
try {
  const jsonMatch = analysisText.match(/```json\n([\s\S]*?)\n```/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[1] : analysisText);
} catch(e) {
  analysis = { fitScore: 0, recommendation: 'error', strengths: [], concerns: ['Parse error'], summary: 'Manual review required', nextSteps: ['Review manually'], technicalScore: 0, communicationScore: 0, cultureFitScore: 0, offerRecommended: false };
}

const webhookData = $('Is Our Interview?').first().json.webhookData;

return [{
  json: {
    'Candidate Name': webhookData.call_data.userName,
    'Interview Date': $now,
    'Duration (minutes)': webhookData.evaluation.duration_minutes,
    'Fit Score': analysis.fitScore,
    'Technical Score': analysis.technicalScore,
    'Communication Score': analysis.communicationScore,
    'Culture Fit Score': analysis.cultureFitScore,
    'Recommendation': analysis.recommendation,
    'Strengths': Array.isArray(analysis.strengths) ? analysis.strengths.join('; ') : '',
    'Concerns': Array.isArray(analysis.concerns) ? analysis.concerns.join('; ') : 'None',
    'Summary': analysis.summary,
    'Next Steps': Array.isArray(analysis.nextSteps) ? analysis.nextSteps.join('; ') : '',
    'Offer Recommended': analysis.offerRecommended,
    'Call ID': webhookData.call_id,
    'Analyzed On': $now,
    offerRecommended: analysis.offerRecommended,
    candidateName: webhookData.call_data.userName
  }
}];

// Generate PDF as base64 using a simple HTML-to-text approach
// In production, use a PDF generation service or n8n's HTML node
// This node prepares the offer data for Telegram document send

const candidateName = $json.candidateName;
const offerContent = $json.offerContent;

// Encode content as base64 for file transmission
const base64Content = Buffer.from(offerContent, 'utf-8').toString('base64');

return [{
  json: {
    candidateName,
    offerContent,
    base64Content,
    fileName: `Offer_Letter_${candidateName.replace(/\s+/g, '_')}.txt`,
    fitScore: $json.fitScore
  }
}];

